export default function RileyWalkthrough() {
  // Owner tour reuses the same shell, switched via ?audience=owner.
  // Read the query directly off window instead of useSearchParams so
  // the page can stay statically prerenderable (useSearchParams pushes
  // the page into Suspense bailout territory in Next 16).
  const [isOwner, setIsOwner] = useState(false);
  useEffect(() => {
    if (typeof window === "undefined") return;
    const params = new URLSearchParams(window.location.search);
    setIsOwner(params.get("audience") === "owner");
  }, []);
  const STEPS = isOwner ? OWNER_STEPS : CAMPER_STEPS;
  const [stepIdx, setStepIdx] = useState(0);
  const [animKey, setAnimKey] = useState(0);
  const [talking, setTalking] = useState(false);
  const [muted, setMuted] = useState(false);
  const [started, setStarted] = useState(false);
  const [imgError, setImgError] = useState(false);
  const audioRef = useRef(null);
  // Cache: stepIdx -> object URL for the prefetched MP3 blob.
  const audioCache = useRef(new Map());
  // Step 1 personalizes the welcome line with the visitor's current
  // check-in campground name. Anonymous visitors fall through to
  // the spec default.
  const [campgroundName, setCampgroundName] = useState("Campground USA");
  const baseStep = STEPS[stepIdx];
  const step = stepIdx === 0
    ? { ...baseStep, speech: baseStep.speech.replace("[Campground Name]", campgroundName) }
    : baseStep;
  // Resolve the visitor's active check-in campground name. Default
  // 'Campground USA' covers anonymous visitors and anyone without an
  // active check-in.
  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const supabase = createSupabaseBrowserClient();
        const { data: { user } } = await supabase.auth.getUser();
        if (!user || cancelled) return;
        const { data: checkIn } = await supabase
          .from("check_ins")
          .select("campground_id")
          .eq("profile_id", user.id)
          .eq("status", "active")
          .gt("expires_at", new Date().toISOString())
          .order("checked_in_at", { ascending: false })
          .limit(1)
          .maybeSingle();
        if (!checkIn || cancelled) return;
        const { data: cg } = await supabase
          .from("campgrounds")
          .select("name")
          .eq("id", checkIn.campground_id)
          .maybeSingle();
        if (!cancelled && cg?.name) setCampgroundName(cg.name);
      } catch {
        // Anonymous visitor / network blip — keep the default.
      }
    })();
    return () => { cancelled = true; };
  }, []);


  // Fetch (and memoize) the audio for a given step. Subsequent calls for the
  // same idx return the cached blob URL instantly.
  const fetchAudio = async (text, idx) => {
    if (audioCache.current.has(idx)) return audioCache.current.get(idx);
    try {
      const res = await fetch("/api/speak", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ text }) });
      if (!res.ok) return null;
      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      audioCache.current.set(idx, url);
      return url;
    } catch (e) {
      return null;
    }
  };

  const speak = async (text, idx) => {
    if (muted) return;
    if (audioRef.current) { audioRef.current.pause(); audioRef.current = null; }
    window.speechSynthesis?.cancel();
    setTalking(true);

    const url = await fetchAudio(text, idx);
    if (url) {
      const audio = new Audio(url);
      audioRef.current = audio;
      audio.onended = () => setTalking(false);
      audio.onerror = () => setTalking(false);
      await audio.play().catch(() => setTalking(false));

      // Kick off the next slide's fetch in the background so it's ready
      // the instant the user taps Next.
      const nextIdx = idx + 1;
      if (nextIdx < STEPS.length) {
        fetchAudio(STEPS[nextIdx].speech, nextIdx).catch(() => {});
      }
      return;
    }

    // Web Speech fallback if /api/speak is unavailable.
    const utt = new SpeechSynthesisUtterance(text);
    const voices = window.speechSynthesis.getVoices();
    const v = voices.find(v => v.name === "Samantha") || voices.find(v => v.lang.startsWith("en"));
    if (v) utt.voice = v;
    utt.rate = 0.85; utt.pitch = 1.0;
    utt.onend = () => setTalking(false);
    utt.onerror = () => setTalking(false);
    window.speechSynthesis.speak(utt);
  };

  useEffect(() => {
    setAnimKey(k => k + 1);
    // Don't try to play before the tap-to-start splash is dismissed —
    // browsers block autoplay without a user gesture.
    if (!started) return;
    // Tightened from 400 → 120 ms; the perceptible lag was mostly this.
    const t = setTimeout(() => speak(step.speech, stepIdx), 120);
    return () => { clearTimeout(t); audioRef.current?.pause(); window.speechSynthesis?.cancel(); setTalking(false); };
  }, [stepIdx, muted, started]);

  // Revoke any cached blob URLs when the page unmounts so we don't leak memory.
  useEffect(() => {
    const cache = audioCache.current;
    return () => {
      cache.forEach((url) => URL.revokeObjectURL(url));
      cache.clear();
    };
  }, []);

  const next = () => { if (stepIdx < STEPS.length - 1) setStepIdx(i => i + 1); };
  const back = () => { if (stepIdx > 0) setStepIdx(i => i - 1); };

  return (
    <div style={{ minHeight: "100vh", background: "linear-gradient(180deg,#071a0e 0%,#0a1a0c 100%)", display: "flex", flexDirection: "column", alignItems: "center", maxWidth: "400px", margin: "0 auto", fontFamily: "Georgia,serif" }}>

      {/* Tap-to-start splash. Covers the whole tour until the user taps,
          which satisfies the browser autoplay gate so Riley's voice fires
          on slide 1 the instant she's introduced. */}
      {!started && (
        <div
          onClick={() => setStarted(true)}
          role="button"
          tabIndex={0}
          aria-label="Tap to meet Riley"
          onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") setStarted(true); }}
          style={{
            position: "fixed",
            inset: 0,
            zIndex: 100,
            background: "radial-gradient(ellipse at center, rgba(245,158,11,0.18) 0%, rgba(7,26,14,0.96) 60%, rgba(7,26,14,0.99) 100%)",
            backdropFilter: "blur(6px)",
            WebkitBackdropFilter: "blur(6px)",
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            justifyContent: "center",
            padding: "32px",
            cursor: "pointer",
            animation: "splashFadeIn 0.4s ease-out",
          }}
        >
          {/* RoadWave logo */}
          <div style={{
            color: "white",
            fontSize: "28px",
            fontWeight: "800",
            letterSpacing: "-0.02em",
            marginBottom: "32px",
            fontFamily: "Georgia,serif",
            display: "inline-flex",
            alignItems: "baseline",
          }}>
            <span>Road</span>
            <span style={{ color: "#f59e0b" }}>Wave</span>
            <span
              className="wave-emoji"
              style={{
                display: "inline-block",
                color: "#f59e0b",
                fontSize: "0.9em",
                marginLeft: "0.12em",
                lineHeight: 1,
              }}
            >
              👋
            </span>
          </div>

          {/* Riley with amber glow */}
          <div style={{
            width: "200px",
            height: "200px",
            borderRadius: "50%",
            overflow: "hidden",
            border: "3px solid #f59e0b",
            boxShadow: "0 0 60px rgba(245,158,11,0.55), 0 0 120px rgba(245,158,11,0.3)",
            animation: "splashGlow 2.4s ease-in-out infinite",
            marginBottom: "28px",
          }}>
            {imgError ? (
              <div style={{ width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center", background: "rgba(245,158,11,0.15)", fontSize: "72px" }}>🏕️</div>
            ) : (
              <img
                src="/riley.png"
                alt="Riley, your campground host"
                onError={() => setImgError(true)}
                style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: "center 18%", display: "block" }}
              />
            )}
          </div>

          {/* Pulsing tap CTA */}
          <div style={{ textAlign: "center", animation: "splashTapPulse 2.2s ease-in-out infinite" }}>
            <p style={{
              fontFamily: "Georgia,serif",
              fontStyle: "italic",
              color: "#f59e0b",
              fontSize: "22px",
              margin: "0 0 8px",
              fontWeight: 600,
            }}>
              Tap anywhere to meet Riley
            </p>
            <p style={{
              color: "rgba(255,255,255,0.55)",
              fontSize: "12px",
              fontFamily: "Georgia,serif",
              margin: 0,
            }}>
              She has a few things to show you
            </p>
          </div>
        </div>
      )}

      {/* String lights */}
      <div style={{ width: "100%", height: "34px", display: "flex", justifyContent: "space-around", alignItems: "flex-start", padding: "0 6px" }}>
        {[...Array(16)].map((_, i) => <div key={i} style={{ width: "7px", height: "7px", borderRadius: "50%", background: ["#ffd700","#ff9f43","#fff","#fde68a"][i%4], boxShadow: `0 0 6px 2px ${["#ffd70055","#ff9f4355","#ffffff44","#fde68a55"][i%4]}`, marginTop: `${3+Math.sin(i)*5}px`, animation: `glow ${1+(i%4)*0.2}s ease-in-out infinite alternate` }} />)}
      </div>

      {/* Header */}
      <div style={{ width: "100%", display: "flex", justifyContent: "space-between", alignItems: "center", padding: "4px 16px" }}>
        <a href="/" style={{ color: "rgba(255,255,255,0.5)", fontSize: "12px", textDecoration: "none" }}>← Exit</a>
        <div style={{ color: "white", fontSize: "13px", fontWeight: "700", display:"flex", alignItems:"center" }}>
          <span>Road</span><span style={{ color: "#f59e0b" }}>Wave</span><span className="wave-emoji" style={{ display: "inline-block", color: "#f59e0b", fontSize: "0.9em", marginLeft: "0.12em", lineHeight: 1 }}>👋</span>
        </div>
        <button onClick={() => setMuted(m => !m)} style={{ background: "none", border: "none", cursor: "pointer", fontSize: "16px", opacity: 0.7 }}>{muted ? "🔇" : "🔊"}</button>
      </div>

      {/* Progress */}
      <div style={{ display: "flex", gap: "5px", alignItems: "center", margin: "6px 0" }}>
        {STEPS.map((_, i) => <div key={i} onClick={() => setStepIdx(i)} style={{ width: i === stepIdx ? "20px" : "6px", height: "6px", borderRadius: "3px", background: i === stepIdx ? "#f59e0b" : i < stepIdx ? "#86efac" : "rgba(255,255,255,0.15)", transition: "all 0.3s", cursor: "pointer" }} />)}
      </div>

      {/* Nav */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", width: "100%", padding: "4px 16px 8px" }}>
        <button onClick={back} disabled={stepIdx === 0} style={{ background: stepIdx===0?"rgba(255,255,255,0.02)":"rgba(255,255,255,0.07)", border: "1px solid rgba(255,255,255,0.1)", borderRadius: "10px", padding: "7px 18px", color: stepIdx===0?"rgba(255,255,255,0.2)":"white", fontSize: "12px", cursor: stepIdx===0?"default":"pointer", fontFamily: "Georgia" }}>← Back</button>
        <div style={{ color: "#6b7280", fontSize: "10px" }}>{stepIdx+1} / {STEPS.length}</div>
        {stepIdx < STEPS.length-1
          ? <button onClick={next} style={{ background: "linear-gradient(135deg,#f59e0b,#d97706)", border: "none", borderRadius: "10px", padding: "7px 18px", color: "#0a0f1c", fontSize: "12px", fontWeight: "700", cursor: "pointer", fontFamily: "Georgia" }}>Next →</button>
          : <div style={{ display: "flex", gap: "6px" }}>
              <a href="/demo" style={{ background: "rgba(255,255,255,0.07)", border: "1px solid rgba(255,255,255,0.15)", borderRadius: "10px", padding: "7px 12px", color: "white", fontSize: "11px", fontWeight: "700", textDecoration: "none", fontFamily: "Georgia" }}>Try the Demo</a>
              <a href="/checkin" style={{ background: "linear-gradient(135deg,#22c55e,#16a34a)", border: "none", borderRadius: "10px", padding: "7px 12px", color: "white", fontSize: "11px", fontWeight: "700", textDecoration: "none", fontFamily: "Georgia" }}>Start Your Check-In</a>
            </div>
        }
      </div>

      {/* Riley */}
      <div key={`r-${animKey}`} style={{ width: "calc(100% - 28px)", borderRadius: "18px", overflow: "hidden", boxShadow: "0 6px 24px rgba(0,0,0,0.6)", animation: "rileyIn 0.4s cubic-bezier(0.34,1.56,0.64,1)", position: "relative", flexShrink: 0 }}>
        <img src={`data:image/png;base64,${RILEY_IMG}`} alt="Riley" style={{ width: "100%", height: "190px", objectFit: "cover", objectPosition: "center 15%", display: "block" }} />
        {talking && (
          <div style={{ position: "absolute", bottom: "8px", left: "50%", transform: "translateX(-50%)", display: "flex", gap: "3px", alignItems: "flex-end", background: "rgba(0,0,0,0.55)", borderRadius: "8px", padding: "4px 8px" }}>
            {[0,1,2,3].map(i => <div key={i} style={{ width: "4px", background: "#f59e0b", borderRadius: "2px", animation: `bar 0.4s ${i*0.1}s ease-in-out infinite alternate` }} />)}
          </div>
        )}
      </div>

      {/* Speech bubble */}
      <div key={`sp-${animKey}`} style={{ background: "rgba(255,255,255,0.05)", border: "1.5px solid rgba(200,169,110,0.3)", borderRadius: "16px", padding: "11px 15px", margin: "8px 14px", fontSize: "12px", color: "rgba(255,255,255,0.9)", lineHeight: "1.6", fontStyle: "italic", animation: "slideUp 0.4s ease", position: "relative", width: "calc(100% - 28px)" }}>
        <div style={{ position: "absolute", top: "-8px", left: "36px", width: 0, height: 0, borderLeft: "8px solid transparent", borderRight: "8px solid transparent", borderBottom: "8px solid rgba(200,169,110,0.3)" }} />
        "{step.speech}"
        <div style={{ color: "#f59e0b", fontSize: "10px", fontStyle: "normal", marginTop: "5px", fontWeight: "600" }}>— Riley 🌲</div>
      </div>

      {/* Phone with highlighted app screen */}
      <div style={{ margin: "8px 14px 0", width: "calc(100% - 28px)", background: "#0d1117", borderRadius: "26px", border: "3px solid rgba(255,255,255,0.12)", overflow: "hidden", boxShadow: "0 8px 28px rgba(0,0,0,0.7)", position: "relative" }}>
        {/* Notch */}
        <div style={{ background: "#060d0a", height: "20px", display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ width: "46px", height: "7px", background: "#1a2a1f", borderRadius: "4px" }} />
        </div>
        {/* Screen */}
        <div key={`sc-${animKey}`} style={{ height: "270px", background: "#0a0f1c", overflowY: "auto", animation: "fadeIn 0.4s ease", position: "relative" }}>
          <AppScreen screen={step.screen} highlight={step.highlight} />
        </div>

        {/* Home bar */}
        <div style={{ background: "#060d0a", height: "16px", display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ width: "46px", height: "4px", background: "#1a2a1f", borderRadius: "2px" }} />
        </div>
      </div>

      {/* Callout bubble — below the phone, centered, with an upward arrow
          pointing at the phone. No longer floats over the screen UI. */}
      {step.bubble && (
        <div key={`bubble-${animKey}`} style={{ display: "flex", flexDirection: "column", alignItems: "center", marginTop: "10px", animation: "bubblePop 0.4s cubic-bezier(0.34,1.56,0.64,1)" }}>
          <div aria-hidden style={{ width: 0, height: 0, borderLeft: "7px solid transparent", borderRight: "7px solid transparent", borderBottom: "7px solid #f59e0b" }} />
          <div style={{ background: "#f59e0b", borderRadius: "20px", padding: "7px 16px", fontSize: "12px", fontWeight: "700", color: "#0a0f1c", whiteSpace: "nowrap", boxShadow: "0 4px 16px rgba(245,158,11,0.5)", fontFamily: "Georgia" }}>
            {step.bubble.text}
          </div>
        </div>
      )}

      <div style={{ height: "20px" }} />

      <style>{`
        @keyframes rileyIn { from{transform:scale(0.93) translateY(8px);opacity:0}to{transform:scale(1);opacity:1} }
        @keyframes slideUp { from{transform:translateY(8px);opacity:0}to{transform:translateY(0);opacity:1} }
        @keyframes fadeIn { from{opacity:0}to{opacity:1} }
        @keyframes bubblePop { from{transform:scale(0.5);opacity:0}to{transform:scale(1);opacity:1} }
        @keyframes glow { from{opacity:0.5}to{opacity:1} }
        @keyframes bar { from{height:4px}to{height:14px} }
        @keyframes float { 0%,100%{transform:translateY(0)}50%{transform:translateY(-8px)} }
        @keyframes hlPulse { 0%,100%{box-shadow:0 0 0 4px rgba(245,158,11,0.2)}50%{box-shadow:0 0 0 8px rgba(245,158,11,0.35)} }
        @keyframes splashFadeIn { from{opacity:0}to{opacity:1} }
        @keyframes splashGlow {
          0%,100% { box-shadow: 0 0 60px rgba(245,158,11,0.55), 0 0 120px rgba(245,158,11,0.3); transform: scale(1); }
          50%     { box-shadow: 0 0 80px rgba(245,158,11,0.7),  0 0 160px rgba(245,158,11,0.45); transform: scale(1.025); }
        }
        @keyframes splashTapPulse {
          0%,100% { opacity: 0.85; transform: scale(1); }
          50%     { opacity: 1;    transform: scale(1.04); }
        }
        @media (prefers-reduced-motion: reduce) {
          [style*="splashGlow"], [style*="splashTapPulse"] { animation: none !important; }
        }
      `}</style>
    </div>
  );
}
